/**
 * /agent command handler — hot-swap between ACP CLI backends
 * (Kiro / Claude Code / Codex) with conversation handoff.
 *
 * /agent          → show current backend + available list
 * /agent <name>   → archive current session → spawn target CLI → new session
 *                   with the handoff archive injected into its preamble
 *
 * Direct-API switching stays on /model — /agent 換人（CLI subprocess），
 * /model 換腦（API endpoint）。
 */
import { Context } from "grammy";
import { config } from "../config.js";
import {
  acpProvidersConfigPath,
  loadAcpProviders,
  seedAcpProvidersFile,
  DEFAULT_BACKEND_KEY,
} from "../acp-providers.js";
import { deps } from "./deps.js";

export async function handleAgent(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat?.id;
  const userId = ctx.from?.id;
  if (!chatId) return;

  const arg = (typeof ctx.match === "string" ? ctx.match : "").trim().toLowerCase();

  // `/agent init` — 設定檔缺失時自動建立範本（保留字，先於 backend lookup 攔截）。
  if (arg === "init") {
    try {
      const result = seedAcpProvidersFile();
      if (!result.created) {
        await ctx.reply(`ℹ️ 設定檔已存在，未覆蓋：\n${result.path}`);
        return;
      }
      const seeded = loadAcpProviders();
      await ctx.reply(
        [
          `✅ 已建立範本設定檔：${result.path}`,
          "",
          ...Object.values(seeded).map(
            (b) => `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}）`,
          ),
          "",
          "scaffold 條目請先確認 command 再切換。編輯檔案即時生效，不需重啟 bridge。",
        ].join("\n"),
        { parse_mode: "Markdown" },
      );
    } catch (err) {
      await ctx.reply(`❌ 建立失敗：${(err as Error).message}`);
    }
    return;
  }

  const backends = loadAcpProviders();
  const session = sessions.peek(chatId);
  const isEnvFallbackOnly =
    Object.keys(backends).length === 1 && backends[DEFAULT_BACKEND_KEY] !== undefined;

  // No argument: show current backend + available list.
  if (!arg) {
    const current = describeCurrent(session?.activeProvider, session?.acpBackend);
    const lines = [
      `🤖 當前 agent：${current}`,
      "",
      "可用 agent：",
      ...Object.values(backends).map((b) => {
        const marker = session?.activeProvider === "acp" && session?.acpBackend === b.key ? " ← 當前" : "";
        const pin = b.model ? `，pin ${b.model}${b.effort ? `/${b.effort}` : ""}` : "";
        return `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}${pin}）${marker}`;
      }),
      "",
      "用法：`/agent <名稱>` 切換（自動交接對話摘要，不掉記憶）",
      "切 Direct API 請用 /model。",
    ];
    if (isEnvFallbackOnly) {
      lines.push(
        "",
        `⚠️ 尚未建立 backend 設定檔，目前只有 .env 預設 agent。`,
        `輸入 /agent init 自動建立範本（${acpProvidersConfigPath()}），或手動建立後即可多 agent 切換。`,
      );
    }
    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    return;
  }

  const def = backends[arg];
  if (!def) {
    await ctx.reply(
      `❌ 未知 agent "${arg}"。可用：${Object.keys(backends).map((k) => `\`${k}\``).join("、")}`,
      { parse_mode: "Markdown" },
    );
    return;
  }

  if (session?.activeProvider === "acp" && session.acpBackend === arg) {
    await ctx.reply(`已經在使用 ${def.label} 了。`);
    return;
  }

  if (session?.inflight) {
    await ctx.reply("⚠️ 目前有 turn 進行中，請等它完成或先 /cancel 再切換。");
    return;
  }

  // exportSession runs the local-LLM handoff summary — takes a few seconds.
  await ctx.reply(`🔄 正在交接對話脈絡並切換到 ${def.label}…`);
  try {
    await sessions.switchAgent(chatId, arg, userId);
    await ctx.reply(
      `✅ 已切換到 **${def.label}**（前段對話摘要已注入新 session）`,
      { parse_mode: "Markdown" },
    );
  } catch (err) {
    await ctx.reply(`❌ 切換失敗：${(err as Error).message}`);
  }
}

function describeCurrent(activeProvider?: string, acpBackend?: string): string {
  if (!activeProvider) return `(尚無 session — 下一則訊息會用 .env 預設 ${config.agent.command} 開啟)`;
  if (activeProvider !== "acp") return `Direct API provider \`${activeProvider}\`（用 /model 管理）`;
  if (acpBackend) {
    const def = loadAcpProviders()[acpBackend];
    return def ? `**${def.label}**（\`${acpBackend}\`）` : `\`${acpBackend}\`（設定檔已無此項）`;
  }
  return `.env 預設（${config.agent.command} ${config.agent.args.join(" ")}）`;
}

/**
 * /model command handler — switch between LLM providers.
 */
import { Context } from "grammy";
import { config } from "../config.js";
import type { ProviderType } from "../provider/types.js";
import { deps } from "./deps.js";

/** Alias map: user-friendly names → ProviderType */
const ALIASES: Record<string, ProviderType> = {
  kiro: "acp",
  acp: "acp",
  claude: "anthropic",
  "claude-api": "anthropic",
  anthropic: "anthropic",
  gpt4o: "openai",
  openai: "openai",
  gpt: "openai",
  gemini: "gemini",
  "gemini-flash": "gemini",
  google: "gemini",
  deepseek: "deepseek",
  groq: "groq",
  llama: "groq",
  local: "local",
  ollama: "local",
};

/** Display info for each provider type. */
const PROVIDER_INFO: Record<ProviderType, { label: string; model: () => string }> = {
  acp: { label: "Kiro CLI (ACP)", model: () => "claude-sonnet-4 via Bedrock" },
  anthropic: { label: "Anthropic API", model: () => config.models.anthropic },
  openai: { label: "OpenAI API", model: () => config.models.openai },
  gemini: { label: "Google Gemini", model: () => config.models.gemini },
  deepseek: { label: "DeepSeek API", model: () => config.models.deepseek },
  groq: { label: "Groq", model: () => config.models.groq },
  local: { label: "Local LLM", model: () => config.models.local },
};

export async function handleModel(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat?.id;
  const userId = ctx.from?.id;
  if (!chatId) return;

  const arg = (typeof ctx.match === "string" ? ctx.match : "").trim().toLowerCase();

  // No argument: show current model + available list
  if (!arg) {
    const session = sessions.peek(chatId);
    const current = session?.activeProvider ?? config.defaultProvider;
    const info = PROVIDER_INFO[current];
    const lines = [
      `🤖 當前模型：**${info.label}** (${info.model()})`,
      "",
      "可用模型：",
      ...Object.entries(PROVIDER_INFO).map(([type, p]) => {
        const marker = type === current ? " ← 當前" : "";
        const available = isAvailable(type as ProviderType);
        return `• \`${type}\` — ${p.label}${available ? "" : " ⚠️ 未設定 API key"}${marker}`;
      }),
      "",
      "用法：`/model <名稱>` 切換",
      "切 ACP CLI agent（Kiro/Claude Code/Codex）請用 /agent（自動交接對話摘要）。",
    ];
    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    return;
  }

  // Resolve alias
  const type = ALIASES[arg];
  if (!type) {
    await ctx.reply(`❌ 未知模型 "${arg}"。用 /model 查看可用列表。`);
    return;
  }

  // Check availability
  if (!isAvailable(type)) {
    const envName = type === "local" ? "OLLAMA_URL" : `${type.toUpperCase()}_API_KEY`;
    await ctx.reply(`❌ ${PROVIDER_INFO[type].label} 未設定（需要 ${envName}）`);
    return;
  }

  // Check if already on this provider
  const session = sessions.peek(chatId);
  if (session?.activeProvider === type) {
    await ctx.reply(`已經在使用 ${PROVIDER_INFO[type].label} 了。`);
    return;
  }

  // Switch
  await ctx.reply(`🔄 切換到 ${PROVIDER_INFO[type].label} (${PROVIDER_INFO[type].model()})...\n⚠️ 對話歷史會重置。`);
  try {
    await (sessions as any).switchProvider(chatId, type, userId);
    await ctx.reply(`✅ 已切換到 **${PROVIDER_INFO[type].label}**`, { parse_mode: "Markdown" });
  } catch (err) {
    await ctx.reply(`❌ 切換失敗：${(err as Error).message}`);
  }
}

function isAvailable(type: ProviderType): boolean {
  if (type === "acp") return true; // always available
  if (type === "local") return true; // Ollama may or may not be running, but config is always there
  const key = type as keyof typeof config.apiKeys;
  return !!config.apiKeys[key];
}

/**
 * ACP backend definition table for /agent hot-swap (SPEC-acp-hot-swap).
 *
 * Backends live in ${MEMORY_DIR}/config/acp-providers.json so each machine
 * keeps its own command lines (npx package forms, local shims, …):
 *
 *   {
 *     "kiro":   { "command": "kiro-cli acp", "label": "Kiro CLI" },
 *     "claude": { "command": "npx claude-agent-acp", "label": "Claude Code",
 *                 "model": "claude-fable-5", "effort": "high" },
 *     "codex":  { "command": "npx @zed-industries/codex-acp", "label": "Codex" }
 *   }
 *
 * `model` / `effort` are per-backend pins sent via session/set_config_option
 * after session/new (the only way that works for claude-agent-acp — its CLI
 * flags are ignored in ACP server mode). When the file is missing or empty
 * the table degrades to a single "default" entry mirroring the .env agent,
 * so /agent stays functional (list + no-op switch) without configuration.
 */
import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { bridgeConfigWritePath, config, resolveBridgeConfigPath } from "./config.js";
import { detectAgentConfigDir } from "./memory.js";

export interface AcpBackendDef {
  /** Table key — what the user types after /agent. */
  key: string;
  command: string;
  args: string[];
  label: string;
  /** Optional per-backend model pin (fuzzy alias ok, e.g. "fable-5"). */
  model?: string;
  /** Optional per-backend reasoning-effort pin ("low"/"medium"/"high"). */
  effort?: string;
}

export const DEFAULT_BACKEND_KEY = "default";

interface RawEntry {
  command?: string;
  label?: string;
  model?: string;
  effort?: string;
}

/**
 * Pure parser — no disk / env access so smoke scripts can exercise it.
 * Entries without a usable command string are skipped. `agentName` replays
 * buildAgent()'s ACP_AGENT_NAME → `--agent <name>` append for kiro commands
 * (the only CLI that takes --agent), so table entries don't lose it.
 */
export function parseAcpProviders(
  raw: string,
  agentName?: string,
): Record<string, AcpBackendDef> {
  const json = JSON.parse(raw) as Record<string, RawEntry>;
  const out: Record<string, AcpBackendDef> = {};
  for (const [key, entry] of Object.entries(json)) {
    if (!entry || typeof entry.command !== "string" || entry.command.trim() === "") continue;
    const parts = entry.command.trim().split(/\s+/);
    const command = parts[0];
    const args = parts.slice(1);
    if (agentName && command.toLowerCase().includes("kiro") && !args.includes("--agent")) {
      args.push("--agent", agentName);
    }
    out[key] = {
      key,
      command,
      args,
      label: entry.label?.trim() || key,
      model: entry.model?.trim() || undefined,
      effort: entry.effort?.trim() || undefined,
    };
  }
  return out;
}

/** Fallback table when acp-providers.json is missing/empty: the .env agent. */
export function defaultBackends(): Record<string, AcpBackendDef> {
  return {
    [DEFAULT_BACKEND_KEY]: {
      key: DEFAULT_BACKEND_KEY,
      command: config.agent.command,
      args: [...config.agent.args],
      label: `${config.agent.command}（.env 預設）`,
      model: config.acpModel || undefined,
      effort: config.acpEffort || undefined,
    },
  };
}

/** Resolved read path (MEMORY_DIR/config first, AGENT_CONFIG_DIR fallback). */
export function acpProvidersConfigPath(): string {
  return resolveBridgeConfigPath("acp-providers.json", detectAgentConfigDir());
}

/** Seed 範本裡的單一 entry（與 RawEntry 同形，export 供 smoke script 斷言）。 */
export interface SeedEntry {
  command: string;
  label: string;
  model?: string;
  effort?: string;
}

/** /agent init 的已知 backend scaffold（command 為常見形式，不保證本機可用）。 */
const KNOWN_BACKENDS: Array<{ key: string; match: RegExp; command: string; label: string }> = [
  { key: "kiro", match: /kiro/i, command: "kiro-cli acp", label: "Kiro CLI" },
  { key: "claude", match: /claude/i, command: "npx claude-agent-acp", label: "Claude Code" },
  { key: "codex", match: /codex/i, command: "npx @zed-industries/codex-acp", label: "Codex" },
];

/**
 * Pure template builder for `/agent init` — no disk / env access so smoke
 * scripts can exercise it. The current .env agent becomes the one guaranteed-
 * valid entry (key inferred from its command line); the other known backends
 * are included as scaffolds whose labels flag that the command needs review.
 */
export function buildSeedTemplate(
  envCommand: string,
  envArgs: string[],
  model?: string,
  effort?: string,
): Record<string, SeedEntry> {
  const envFull = [envCommand, ...envArgs].join(" ").trim();
  const matched = KNOWN_BACKENDS.find((b) => b.match.test(envFull));
  const envKey = matched?.key ?? DEFAULT_BACKEND_KEY;
  const out: Record<string, SeedEntry> = {
    [envKey]: {
      command: envFull,
      label: `${matched?.label ?? envKey}（.env 當前 agent）`,
      model: model || undefined,
      effort: effort || undefined,
    },
  };
  for (const b of KNOWN_BACKENDS) {
    if (b.key === envKey) continue;
    out[b.key] = { command: b.command, label: `${b.label}（scaffold，請確認 command）` };
  }
  return out;
}

/**
 * Write the seed template to the primary config location. Never overwrites:
 * if the file already exists (primary or AGENT_CONFIG_DIR fallback) it
 * returns `created: false` with that path.
 */
export function seedAcpProvidersFile(): { path: string; created: boolean } {
  const existing = acpProvidersConfigPath();
  if (existsSync(existing)) return { path: existing, created: false };
  const target = bridgeConfigWritePath("acp-providers.json");
  const template = buildSeedTemplate(
    config.agent.command,
    config.agent.args,
    config.acpModel || undefined,
    config.acpEffort || undefined,
  );
  writeFileSync(target, JSON.stringify(template, null, 2) + "\n", "utf8");
  return { path: target, created: true };
}

export function loadAcpProviders(): Record<string, AcpBackendDef> {
  try {
    const raw = readFileSync(acpProvidersConfigPath(), "utf8");
    const parsed = parseAcpProviders(
      raw,
      (process.env.ACP_AGENT_NAME ?? "").trim() || undefined,
    );
    if (Object.keys(parsed).length > 0) return parsed;
  } catch {
    /* missing or unparseable — degrade to the .env agent */
  }
  return defaultBackends();
}

