    32→  if (arg === "init") {
    33→    try {
    34→      const result = seedAcpProvidersFile();
    35→      if (!result.created) {
    36→        await ctx.reply(`ℹ️ 設定檔已存在，未覆蓋：\n${result.path}`);
    37→        return;
    38→      }
    39→      const seeded = loadAcpProviders();
    40→      await ctx.reply(
