    42→          `✅ 已建立範本設定檔：${result.path}`,
    43→          "",
    44→          ...Object.values(seeded).map(
    45→            (b) => `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}）`,
