    47→          "",
    48→          "scaffold 條目請先確認 command 再切換。編輯檔案即時生效，不需重啟 bridge。",
    49→        ].join("\n"),
    50→        { parse_mode: "Markdown" },
    51→      );
    52→    } catch (err) {
    53→      await ctx.reply(`❌ 建立失敗：${(err as Error).message}`);
    54→    }
    55→    return;
    56→  }
    57→
    58→  const backends = loadAcpProviders();
    59→  const session = sessions.peek(chatId);
    60→  const isEnvFallbackOnly =
    61→    Object.keys(backends).length === 1 && backends[DEFAULT_BACKEND_KEY] !== undefined;
    62→
    63→  // No argument: show current backend + available list.
    64→  if (!arg) {
    65→    const current = describeCurrent(session?.activeProvider, session?.acpBackend);
    66→    const lines = [
    67→      `🤖 當前 agent：${current}`,
    68→      "",
    69→      "可用 agent：",
    70→      ...Object.values(backends).map((b) => {
    71→        const marker = session?.activeProvider === "acp" && session?.acpBackend === b.key ? " ← 當前" : "";
    72→        const pin = b.model ? `，pin ${b.model}${b.effort ? `/${b.effort}` : ""}` : "";
    73→        return `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}${pin}）${marker}`;
    74→      }),
    75→      "",
    76→      "用法：`/agent <名稱>` 切換（自動交接對話摘要，不掉記憶）",
    77→      "切 Direct API 請用 /model。",
    78→    ];
    79→    if (isEnvFallbackOnly) {
    80→      lines.push(
    81→        "",
    82→        `⚠️ 尚未建立 backend 設定檔，目前只有 .env 預設 agent。`,
    83→        `輸入 /agent init 自動建立範本（${acpProvidersConfigPath()}），或手動建立後即可多 agent 切換。`,
    84→      );
    85→    }
    86→    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    87→    return;
    88→  }
    89→
    90→  const def = backends[arg];
    91→  if (!def) {
    92→    await ctx.reply(
    93→      `❌ 未知 agent "${arg}"。可用：${Object.keys(backends).map((k) => `\`${k}\``).join("、")}`,
    94→      { parse_mode: "Markdown" },
    95→    );
    96→    return;
    97→  }
    98→
    99→  if (session?.activeProvider === "acp" && session.acpBackend === arg) {
   100→    await ctx.reply(`已經在使用 ${def.label} 了。`);
   101→    return;
   102→  }
   103→
   104→  if (session?.inflight) {
   105→    await ctx.reply("⚠️ 目前有 turn 進行中，請等它完成或先 /cancel 再切換。");
   106→    return;
   107→  }
   108→
   109→  // exportSession runs the local-LLM handoff summary — takes a few seconds.
   110→  await ctx.reply(`🔄 正在交接對話脈絡並切換到 ${def.label}…`);
   111→  try {
   112→    await sessions.switchAgent(chatId, arg, userId);
   113→    await ctx.reply(
   114→      `✅ 已切換到 **${def.label}**（前段對話摘要已注入新 session）`,
   115→      { parse_mode: "Markdown" },
   116→    );
   117→  } catch (err) {
   118→    await ctx.reply(`❌ 切換失敗：${(err as Error).message}`);
   119→  }
   120→}
   121→
   122→function describeCurrent(activeProvider?: string, acpBackend?: string): string {
   123→  if (!activeProvider) return `(尚無 session — 下一則訊息會用 .env 預設 ${config.agent.command} 開啟)`;
   124→  if (activeProvider !== "acp") return `Direct API provider \`${activeProvider}\`（用 /model 管理）`;
   125→  if (acpBackend) {
   126→    const def = loadAcpProviders()[acpBackend];
   127→    return def ? `**${def.label}**（\`${acpBackend}\`）` : `\`${acpBackend}\`（設定檔已無此項）`;
   128→  }
   129→  return `.env 預設（${config.agent.command} ${config.agent.args.join(" ")}）`;
   130→}
