    11→ *     "codex":  { "command": "npx @zed-industries/codex-acp", "label": "Codex" }
    12→ *   }
    13→ *
    14→ * `model` / `effort` are per-backend pins sent via session/set_config_option
    15→ * after session/new (the only way that works for claude-agent-acp — its CLI
    16→ * flags are ignored in ACP server mode). When the file is missing or empty
    17→ * the table degrades to a single "default" entry mirroring the .env agent,
    18→ * so /agent stays functional (list + no-op switch) without configuration.
    19→ */
    20→import { existsSync, readFileSync, writeFileSync } from "node:fs";
    21→import { bridgeConfigWritePath, config, resolveBridgeConfigPath } from "./config.js";
    22→import { detectAgentConfigDir } from "./memory.js";
    23→
    24→export interface AcpBackendDef {
    25→  /** Table key — what the user types after /agent. */
    26→  key: string;
    27→  command: string;
    28→  args: string[];
    29→  label: string;
    30→  /** Optional per-backend model pin (fuzzy alias ok, e.g. "fable-5"). */
    31→  model?: string;
    32→  /** Optional per-backend reasoning-effort pin ("low"/"medium"/"high"). */
    33→  effort?: string;
    34→}
    35→
    36→export const DEFAULT_BACKEND_KEY = "default";
    37→
    38→interface RawEntry {
    39→  command?: string;
    40→  label?: string;
    41→  model?: string;
    42→  effort?: string;
    43→}
    44→
    45→/**
    46→ * Pure parser — no disk / env access so smoke scripts can exercise it.
    47→ * Entries without a usable command string are skipped. `agentName` replays
    48→ * buildAgent()'s ACP_AGENT_NAME → `--agent <name>` append for kiro commands
    49→ * (the only CLI that takes --agent), so table entries don't lose it.
    50→ */
    51→export function parseAcpProviders(
    52→  raw: string,
    53→  agentName?: string,
    54→): Record<string, AcpBackendDef> {
    55→  const json = JSON.parse(raw) as Record<string, RawEntry>;
    56→  const out: Record<string, AcpBackendDef> = {};
    57→  for (const [key, entry] of Object.entries(json)) {
    58→    if (!entry || typeof entry.command !== "string" || entry.command.trim() === "") continue;
    59→    const parts = entry.command.trim().split(/\s+/);
    60→    const command = parts[0];
    61→    const args = parts.slice(1);
    62→    if (agentName && command.toLowerCase().includes("kiro") && !args.includes("--agent")) {
    63→      args.push("--agent", agentName);
    64→    }
    65→    out[key] = {
    66→      key,
    67→      command,
    68→      args,
    69→      label: entry.label?.trim() || key,
    70→      model: entry.model?.trim() || undefined,
    71→      effort: entry.effort?.trim() || undefined,
    72→    };
    73→  }
    74→  return out;
    75→}
    76→
    77→/** Fallback table when acp-providers.json is missing/empty: the .env agent. */
    78→export function defaultBackends(): Record<string, AcpBackendDef> {
    79→  return {
    80→    [DEFAULT_BACKEND_KEY]: {
    81→      key: DEFAULT_BACKEND_KEY,
    82→      command: config.agent.command,
    83→      args: [...config.agent.args],
    84→      label: `${config.agent.command}（.env 預設）`,
    85→      model: config.acpModel || undefined,
    86→      effort: config.acpEffort || undefined,
    87→    },
    88→  };
    89→}
    90→
    91→/** Resolved read path (MEMORY_DIR/config first, AGENT_CONFIG_DIR fallback). */
    92→export function acpProvidersConfigPath(): string {
    93→  return resolveBridgeConfigPath("acp-providers.json", detectAgentConfigDir());
    94→}
    95→
    96→/** Seed 範本裡的單一 entry（與 RawEntry 同形，export 供 smoke script 斷言）。 */
    97→export interface SeedEntry {
    98→  command: string;
    99→  label: string;
   100→  model?: string;
   101→  effort?: string;
   102→}
   103→
   104→/** /agent init 的已知 backend scaffold（command 為常見形式，不保證本機可用）。 */
   105→const KNOWN_BACKENDS: Array<{ key: string; match: RegExp; command: string; label: string }> = [
   106→  { key: "kiro", match: /kiro/i, command: "kiro-cli acp", label: "Kiro CLI" },
   107→  { key: "claude", match: /claude/i, command: "npx claude-agent-acp", label: "Claude Code" },
   108→  { key: "codex", match: /codex/i, command: "npx @zed-industries/codex-acp", label: "Codex" },
   109→];
   110→
   111→/**
   112→ * Pure template builder for `/agent init` — no disk / env access so smoke
   113→ * scripts can exercise it. The current .env agent becomes the one guaranteed-
   114→ * valid entry (key inferred from its command line); the other known backends
   115→ * are included as scaffolds whose labels flag that the command needs review.
   116→ */
   117→export function buildSeedTemplate(
   118→  envCommand: string,
   119→  envArgs: string[],
   120→  model?: string,
   121→  effort?: string,
   122→): Record<string, SeedEntry> {
   123→  const envFull = [envCommand, ...envArgs].join(" ").trim();
   124→  const matched = KNOWN_BACKENDS.find((b) => b.match.test(envFull));
   125→  const envKey = matched?.key ?? DEFAULT_BACKEND_KEY;
   126→  const out: Record<string, SeedEntry> = {
   127→    [envKey]: {
   128→      command: envFull,
   129→      label: `${matched?.label ?? envKey}（.env 當前 agent）`,
   130→      model: model || undefined,
   131→      effort: effort || undefined,
   132→    },
   133→  };
   134→  for (const b of KNOWN_BACKENDS) {
   135→    if (b.key === envKey) continue;
   136→    out[b.key] = { command: b.command, label: `${b.label}（scaffold，請確認 command）` };
   137→  }
   138→  return out;
   139→}
   140→
   141→/**
   142→ * Write the seed template to the primary config location. Never overwrites:
   143→ * if the file already exists (primary or AGENT_CONFIG_DIR fallback) it
   144→ * returns `created: false` with that path.
   145→ */
   146→export function seedAcpProvidersFile(): { path: string; created: boolean } {
   147→  const existing = acpProvidersConfigPath();
   148→  if (existsSync(existing)) return { path: existing, created: false };
   149→  const target = bridgeConfigWritePath("acp-providers.json");
   150→  const template = buildSeedTemplate(
   151→    config.agent.command,
   152→    config.agent.args,
   153→    config.acpModel || undefined,
   154→    config.acpEffort || undefined,
   155→  );
   156→  writeFileSync(target, JSON.stringify(template, null, 2) + "\n", "utf8");
   157→  return { path: target, created: true };
   158→}
   159→
   160→export function loadAcpProviders(): Record<string, AcpBackendDef> {
   161→  try {
   162→    const raw = readFileSync(acpProvidersConfigPath(), "utf8");
   163→    const parsed = parseAcpProviders(
   164→      raw,
   165→      (process.env.ACP_AGENT_NAME ?? "").trim() || undefined,
   166→    );
   167→    if (Object.keys(parsed).length > 0) return parsed;
   168→  } catch {
   169→    /* missing or unparseable — degrade to the .env agent */
   170→  }
   171→  return defaultBackends();
   172→}
   173→
