  promptRetryBaseMs?: number;
  /**
   * Pin the ACP session's model right after session/new via
   * `session/set_config_option`. Accepts the adapter's canonical model id or a
   * fuzzy alias (e.g. "fable-5"). Only adapters that expose a "model" config
   * option (currently claude-agent-acp) honour it; others reject and we log.
   * Empty/undefined = leave the agent's own default untouched.
   */
  acpModel?: string;
  /**
   * Pin the session's reasoning effort (e.g. "low"/"medium"/"high") after the
   * model is set. Must exactly match a value the selected model supports —
   * unlike model, there is no fuzzy fallback. Empty/undefined = untouched.
   */
  acpEffort?: string;
}

/**
 * Errors where the agent's cloud backend aborted the response stream. These
 * are almost always worth retrying (network blip, TLS reset, 5xx from the
 * upstream provider). We detect by error code + message/data fingerprints,
 * since kiro-cli wraps them as generic JSON-RPC -32603 Internal error.
 */
function isTransientBackendError(err: unknown): boolean {
  if (!err || typeof err !== "object") return false;
  const e = err as { code?: number; message?: string; data?: unknown };
  if (e.code !== -32603) return false;

