console.log(`[acpClient module-load] process.env.PATH length=${process.env.PATH?.length ?? 0}, FULL_SYSTEM_PATH length=${FULL_SYSTEM_PATH.length}`);

let _spawnEnvLogged = false;
function buildSpawnEnv(extra?: Record<string, string | undefined>): NodeJS.ProcessEnv {
  const base = { ...process.env, ...(extra ?? {}) };

  // Telegram 同一 token 只允許一個 getUpdates 消費者。宿主的 bot token 若洩漏給
  // 子 agent，Claude Code 的 telegram plugin（環境變數優先於自身設定檔）會拿
  // 同一 token 去 poll，把 bridge 自己 409 打死。設成空字串（而非 delete）：
  // plugin 看到「已定義但為空」不會 fallback 讀自己的設定檔，會直接自我停用——
  // bridge spawn 的 headless session 本來就不該再開一條 Telegram channel。
  base.TELEGRAM_BOT_TOKEN = "";

  if (process.platform === "win32") {
    const sysRoot = process.env.SystemRoot ?? "C:\\Windows";
    const sys32 = path.join(sysRoot, "System32");
    base.SystemRoot ??= sysRoot;
    base.COMSPEC ??= path.join(sys32, "cmd.exe");
    base.PATHEXT ??= ".COM;.EXE;.BAT;.CMD;.VBS;.VBE;.JS;.JSE;.WSF;.WSH;.MSC;.PS1";
    // Merge registry PATH entries into the runtime PATH (don't replace —
    // runtime PATH may include npm/Kiro-Cli dirs not in registry)
    const raw = base.PATH ?? base.Path ?? "";
    if (FULL_SYSTEM_PATH) {
      const existing = new Set(raw.split(";").map(p => p.toLowerCase()));
      const extras = FULL_SYSTEM_PATH.split(";").filter(p => p && !existing.has(p.toLowerCase()));
      if (extras.length) base.PATH = raw + ";" + extras.join(";");
    }
  }

  // Diagnostic: log once on first call
  if (process.platform === "win32" && !_spawnEnvLogged) {
    _spawnEnvLogged = true;
    console.log(`[buildSpawnEnv] RAW process.env.PATH=${process.env.PATH ?? "undefined"}`);
    console.log(`[buildSpawnEnv] RAW process.env.Path=${process.env.Path ?? "undefined"}`);
    console.log(`[buildSpawnEnv] FINAL PATH=${base.PATH}`);
    console.log(`[buildSpawnEnv] COMSPEC=${base.COMSPEC}`);
    console.log(`[buildSpawnEnv] SystemRoot=${base.SystemRoot}`);
  }

  return base;
}

