// Smoke: verify the bridge pins ACP model / effort via session/set_config_option.
//
// Spawns the ACP agent (default: ACP_AGENT_COMMAND, else "claude-agent-acp"),
// runs the bridge handshake with acpModel/acpEffort set, and checks that the
// adapter accepted each option — detected by the "[acp] pinned <id>=<value>"
// stderr line AcpClient.applyModelEffort emits on success. A "not applied"
// line (unknown method / invalid value / dead stream) fails the check and
// prints the adapter's reason.
//
// Run (uses .env's ACP_AGENT_COMMAND — must be a Claude adapter):
//   node scripts/check-acp-model-effort.mjs
//   node scripts/check-acp-model-effort.mjs --model claude-fable-5 --effort medium
//   node scripts/check-acp-model-effort.mjs claude-agent-acp --model fable-5
//
// Uses compiled dist/acpClient.js — run `npx tsc` first.
//
// Exit codes: 0 = both requested options pinned; 1 = failure/rejection; 2 = bad usage.

import "dotenv/config";
import { AcpClient } from "../dist/acpClient.js";

function parseArgs(argv) {
  let model = "claude-fable-5";
  let effort = "medium";
  let timeoutMs = 30_000;
  const rest = [];
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--model") { model = argv[++i]; }
    else if (a === "--effort") { effort = argv[++i]; }
    else if (a === "--timeout" || a === "-t") { timeoutMs = Number(argv[++i]); }
    else rest.push(a);
  }
  if (!Number.isFinite(timeoutMs) || timeoutMs <= 0) {
    console.error("error: --timeout expects a positive number");
    process.exit(2);
  }
  // Command: explicit argv wins, else fall back to the bridge's .env value.
  let command, args;
  if (rest.length > 0) {
    command = rest[0];
    args = rest.slice(1);
  } else {
    const raw = (process.env.ACP_AGENT_COMMAND ?? "claude-agent-acp").trim().split(/\s+/);
    command = raw[0];
    args = raw.slice(1);
  }
  return { command, args, model, effort, timeoutMs };
}

function withTimeout(promise, ms, label) {
  let timer;
  const timeout = new Promise((_, reject) => {
    timer = setTimeout(() => reject(new Error(`${label} timed out after ${ms}ms`)), ms);
  });
  return Promise.race([promise.finally(() => clearTimeout(timer)), timeout]);
}

const { command, args, model, effort, timeoutMs } = parseArgs(process.argv.slice(2));

console.log(`[check-model-effort] command: ${command}${args.length ? " " + args.join(" ") : ""}`);
console.log(`[check-model-effort] pinning: model=${model} effort=${effort}`);
console.log(`[check-model-effort] --- spawning agent ---`);

const client = new AcpClient({
  command,
  args,
  cwd: process.cwd(),
  promptRetries: 0,
  acpModel: model,
  acpEffort: effort,
});

// applyModelEffort emits "[acp] pinned <id>=..." on success and
// "[acp] set <id>=... not applied (ignored): <reason>" on rejection.
const pinned = new Set();
const rejected = new Map();
client.on("stderr", (chunk) => {
  process.stderr.write(`[agent-stderr] ${chunk}`);
  const okM = /\[acp\] pinned (\w+)=/.exec(chunk);
  if (okM) pinned.add(okM[1]);
  const badM = /\[acp\] set (\w+)=.* not applied \(ignored\): (.*)/.exec(chunk);
  if (badM) rejected.set(badM[1], badM[2].trim());
});

let exitCode = 0;
try {
  const sessionId = await withTimeout(
    client.initializeAndCreateSession(process.cwd()),
    timeoutMs,
    "initialize + session/new + set_config_option",
  );
  console.log(`[check-model-effort] handshake OK, sessionId=${sessionId}`);

  for (const [id, want] of [["model", model], ["effort", effort]]) {
    if (pinned.has(id)) {
      console.log(`✅ ${id} pinned to "${want}"`);
    } else if (rejected.has(id)) {
      exitCode = 1;
      console.error(`❌ ${id}="${want}" rejected: ${rejected.get(id)}`);
    } else {
      exitCode = 1;
      console.error(`❌ ${id}="${want}" — no confirmation seen (adapter may not support it)`);
    }
  }
  if (exitCode === 0) console.log(`\n✅ model + effort successfully pinned via session/set_config_option.`);
} catch (err) {
  exitCode = 1;
  console.error(`[check-model-effort] FAILED: ${(err && err.message) || String(err)}`);
} finally {
  await client.close().catch(() => {});
}

setTimeout(() => process.exit(exitCode), 150);

