    30→    else if (a === "--effort") { effort = argv[++i]; }
    31→    else if (a === "--timeout" || a === "-t") { timeoutMs = Number(argv[++i]); }
    32→    else rest.push(a);
    33→  }
    34→  if (!Number.isFinite(timeoutMs) || timeoutMs <= 0) {
    35→    console.error("error: --timeout expects a positive number");
    36→    process.exit(2);
    37→  }
    38→  // Command: explicit argv wins, else fall back to the bridge's .env value.
    39→  let command, args;
    40→  if (rest.length > 0) {
    41→    command = rest[0];
    42→    args = rest.slice(1);
    43→  } else {
    44→    const raw = (process.env.ACP_AGENT_COMMAND ?? "claude-agent-acp").trim().split(/\s+/);
    45→    command = raw[0];
    46→    args = raw.slice(1);
    47→  }
    48→  return { command, args, model, effort, timeoutMs };
    49→}
    50→
    51→function withTimeout(promise, ms, label) {
    52→  let timer;
    53→  const timeout = new Promise((_, reject) => {
    54→    timer = setTimeout(() => reject(new Error(`${label} timed out after ${ms}ms`)), ms);
    55→  });
    56→  return Promise.race([promise.finally(() => clearTimeout(timer)), timeout]);
    57→}
    58→
    59→const { command, args, model, effort, timeoutMs } = parseArgs(process.argv.slice(2));
    60→
    61→console.log(`[check-model-effort] command: ${command}${args.length ? " " + args.join(" ") : ""}`);
    62→console.log(`[check-model-effort] pinning: model=${model} effort=${effort}`);
    63→console.log(`[check-model-effort] --- spawning agent ---`);
    64→
    65→const client = new AcpClient({
    66→  command,
    67→  args,
    68→  cwd: process.cwd(),
    69→  promptRetries: 0,
    70→  acpModel: model,
    71→  acpEffort: effort,
    72→});
    73→
    74→// applyModelEffort emits "[acp] pinned <id>=..." on success and
    75→// "[acp] set <id>=... not applied (ignored): <reason>" on rejection.
    76→const pinned = new Set();
    77→const rejected = new Map();
    78→client.on("stderr", (chunk) => {
    79→  process.stderr.write(`[agent-stderr] ${chunk}`);
    80→  const okM = /\[acp\] pinned (\w+)=/.exec(chunk);
    81→  if (okM) pinned.add(okM[1]);
    82→  const badM = /\[acp\] set (\w+)=.* not applied \(ignored\): (.*)/.exec(chunk);
    83→  if (badM) rejected.set(badM[1], badM[2].trim());
    84→});
    85→
    86→let exitCode = 0;
    87→try {
    88→  const sessionId = await withTimeout(
    89→    client.initializeAndCreateSession(process.cwd()),
    90→    timeoutMs,
    91→    "initialize + session/new + set_config_option",
    92→  );
    93→  console.log(`[check-model-effort] handshake OK, sessionId=${sessionId}`);
    94→
    95→  for (const [id, want] of [["model", model], ["effort", effort]]) {
    96→    if (pinned.has(id)) {
    97→      console.log(`✅ ${id} pinned to "${want}"`);
    98→    } else if (rejected.has(id)) {
    99→      exitCode = 1;
   100→      console.error(`❌ ${id}="${want}" rejected: ${rejected.get(id)}`);
   101→    } else {
   102→      exitCode = 1;
   103→      console.error(`❌ ${id}="${want}" — no confirmation seen (adapter may not support it)`);
   104→    }
   105→  }
   106→  if (exitCode === 0) console.log(`\n✅ model + effort successfully pinned via session/set_config_option.`);
   107→} catch (err) {
   108→  exitCode = 1;
   109→  console.error(`[check-model-effort] FAILED: ${(err && err.message) || String(err)}`);
   110→} finally {
   111→  await client.close().catch(() => {});
   112→}
   113→
   114→setTimeout(() => process.exit(exitCode), 150);
